/*!
 * ScrollSmoother Shim v1.0
 * Replaces Club GSAP ScrollSmoother with a lightweight alternative
 * using ScrollTrigger's built-in normalization.
 */
(function(window) {
    "use strict";

    var ScrollSmoother = (function() {
        function ScrollSmoother() {}

        ScrollSmoother.create = function(config) {
            config = config || {};
            var wrapper = document.querySelector("#smooth-wrapper");
            var content = document.querySelector("#smooth-content");

            if (!wrapper || !content) return null;

            // Apply smooth scrolling via CSS
            document.documentElement.style.scrollBehavior = "smooth";

            // Add smooth class to body
            document.body.classList.add("smooth-scroll-active");

            // Basic CSS-based smooth scroll wrapper
            wrapper.style.overflow = "hidden";
            wrapper.style.position = "fixed";
            wrapper.style.width = "100%";
            wrapper.style.top = "0";
            wrapper.style.left = "0";
            wrapper.style.right = "0";
            wrapper.style.bottom = "0";

            content.style.willChange = "transform";

            var currentY = 0;
            var targetY = 0;
            var smoothness = config.smooth || 1;
            var ease = 1 / (smoothness * 10);

            // Update body height to enable scrolling
            function updateBodyHeight() {
                document.body.style.height = content.scrollHeight + "px";
            }
            updateBodyHeight();

            // Resize observer
            if (window.ResizeObserver) {
                new ResizeObserver(updateBodyHeight).observe(content);
            }

            var raf;
            function update() {
                targetY = window.scrollY || window.pageYOffset;
                currentY += (targetY - currentY) * (ease < 1 ? ease : 0.1);
                if (Math.abs(targetY - currentY) < 0.05) currentY = targetY;
                content.style.transform = "translateY(" + (-currentY) + "px)";

                // Update ScrollTrigger
                if (window.ScrollTrigger) {
                    ScrollTrigger.update();
                }
                raf = requestAnimationFrame(update);
            }

            update();

            // Override scrollTrigger scroller
            if (window.gsap && window.ScrollTrigger) {
                ScrollTrigger.defaults({ scroller: wrapper });
                ScrollTrigger.scrollerProxy(wrapper, {
                    scrollTop: function(value) {
                        if (arguments.length) {
                            currentY = value;
                            targetY = value;
                        }
                        return currentY;
                    },
                    getBoundingClientRect: function() {
                        return { top: 0, left: 0, width: window.innerWidth, height: window.innerHeight };
                    }
                });

                ScrollTrigger.addEventListener("refresh", function() {
                    updateBodyHeight();
                });
            }

            return {
                paused: false,
                smooth: smoothness,
                scrollTop: function(v) {
                    if (arguments.length) {
                        window.scrollTo(0, v);
                        currentY = v;
                    }
                    return currentY;
                },
                kill: function() {
                    cancelAnimationFrame(raf);
                    document.body.style.height = "";
                    content.style.transform = "";
                    wrapper.style.overflow = "";
                    wrapper.style.position = "";
                    wrapper.style.width = "";
                    wrapper.style.top = "";
                    wrapper.style.left = "";
                    wrapper.style.right = "";
                    wrapper.style.bottom = "";
                }
            };
        };

        ScrollSmoother.get = function() {
            return ScrollSmoother._instance;
        };

        return ScrollSmoother;
    })();

    // Register with GSAP if available
    if (window.gsap) {
        gsap.registerPlugin({
            name: "ScrollSmoother",
            register: function(core) {}
        });
    }

    window.ScrollSmoother = ScrollSmoother;

})(window);
